mapper.select:
SELECT c.id AS id, class_name, classroom, e.name AS teacherName, start_date, end_date, cs.status_name AS classStatus, c.update_time AS updateTime FROM class c LEFT JOIN emp_info e ON c.teacher_id = e.id LEFT JOIN class_status cs ON c.status = cs.id
class_name LIKE CONCAT('%', #{className}, '%')
AND start_date >= #{begin}
AND end_date <= #{end}
